// Format payload for InfluxDB HTTP API (line protocol)
// IMPORTANT: Use .toFixed() on all float fields.
// When anomaly_score=0 exactly, ArduinoJson emits integer 0 in JSON.
// Without toFixed(), line protocol gets 'anomaly_score=0' (integer type)
// which conflicts with the existing float field type => 400 Bad Request.
var d = msg.payload;
var line = 'conveyor_belt'
  + ' x=' + Number(d.x).toFixed(4)
  + ',y=' + Number(d.y).toFixed(4)
  + ',z=' + Number(d.z).toFixed(4)
  + ',magnitude=' + Number(d.magnitude).toFixed(4)
  + ',temperature=' + Number(d.temperature || 0).toFixed(2)
  + ',anomaly_score=' + Number(d.anomaly_score).toFixed(4)
  + ',fault_flag=' + d.fault_flag + 'i'
  + ',relay_state=' + d.relay_state + 'i'
  + ',consecutive_faults=' + (d.consecutive_faults || 0) + 'i'
  + ',fault_type="' + d.fault_type + '"'
  + ',mode="' + (d.mode || 'unknown') + '"';
msg.payload = line;
return msg;

var d = msg.payload;
if (typeof d === 'string') d = JSON.parse(d);
if (d.fault_flag === 1) {
    msg.payload = '⚠ FAULT: ' + d.fault_type
      + ' | Score: ' + d.anomaly_score
      + ' | Consecutive: ' + (d.consecutive_faults || '?');
    return msg;
}
return null; // Only pass faults

// ── RUL Estimation using Ordinary Least Squares (OLS) ──
// Rolling window of last 60 anomaly_score values (30s at 2Hz)
// Computes slope via linear regression, then estimates
// minutes until anomaly_score reaches 1.0

var WINDOW = 60;
var d = msg.payload;
if (typeof d === 'string') d = JSON.parse(d);

// Retrieve or initialise rolling buffer
var scores = flow.get('rul_scores') || [];
scores.push(d.anomaly_score);
if (scores.length > WINDOW) scores.shift();
flow.set('rul_scores', scores);

var n = scores.length;
if (n < 5) return null; // Need at least 5 samples

// OLS linear regression: y = a + b*x
var sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0;
for (var i = 0; i < n; i++) {
    sumX  += i;
    sumY  += scores[i];
    sumXY += i * scores[i];
    sumX2 += i * i;
}

var slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
var current_score = scores[n - 1];

// RUL = time until score reaches 1.0
// Each sample is 0.5 seconds apart (2 Hz)
// slope is per-sample, so convert to per-minute
// RUL is only meaningful when the system is actively degrading (positive slope).
// A zero or negative slope means the system is stable or improving — no countdown.
var rul_minutes;
var stable = false;
if (slope <= 0) {
    rul_minutes = 999; // Stable / improving — display max, not a fake countdown
    stable = true;
} else {
    var samples_to_failure = (1.0 - current_score) / slope;
    rul_minutes = (samples_to_failure * 0.5) / 60.0;
    if (rul_minutes < 0) rul_minutes = 0;
    if (rul_minutes > 999) rul_minutes = 999;
}

// Format for InfluxDB line protocol
var line = 'rul_estimate'
  + ' rul_minutes=' + rul_minutes.toFixed(2)
  + ',slope=' + slope.toFixed(6)
  + ',current_score=' + current_score
  + ',stable=' + (stable ? 'true' : 'false');

msg.payload = line;
msg.rul_minutes = rul_minutes;
msg.slope = slope;
msg.stable = stable;
return msg;

// Accept POST {"relay_command": "ON"} or {"relay_command": "OFF"}
var cmd = msg.payload.relay_command || 'OFF';
msg.payload = JSON.stringify({relay_command: cmd});
msg.res_payload = {status: 'ok', relay_command: cmd};
return msg;
